import miniworlds

world = miniworlds.World(400, 300)
world.add_background((30, 30, 30))

follower = miniworlds.Circle((200, 150), 20)
follower.color = (0, 220, 255)
follower.is_following = False
follower._moves = 0

@world.register
def on_mouse_left_down(self, position):
    follower.is_following = not follower.is_following
    print("FOLLOW:", "ON" if follower.is_following else "OFF",
          "click_at:", int(position[0]), int(position[1]))

@follower.register
def act(self):
    if self.is_following:
        mouse_pos = world.mouse.get_position()
        if mouse_pos:
            self.move_towards(mouse_pos)
            self._moves += 1
            if self._moves <= 5:
                print("TARGET:", int(mouse_pos[0]), int(mouse_pos[1]))

world.run()
